$(document).ready(function(){var e=document.querySelector(".header-two__menu-catalog");e&&new PerfectScrollbar(e,{wheelSpeed:.5,wheelPropagation:!0,minScrollbarLength:20});let r=document.querySelectorAll(".header-two__nav-submenu");if(r)for(let e=0;r.length>e;e++)new PerfectScrollbar(r[e],{wheelSpeed:.5,wheelPropagation:!0,minScrollbarLength:20,typeContainer:"li"})});